5609     //     br scalar.body
5610     //
5611     //   scalar.body:
5612     //     i = phi [0, scalar.ph], [i+1, scalar.body]
5613     //     s1 = phi [s.init, scalar.ph], [s2, scalar.body]
5614     //     s2 = a[i]
5615     //     b[i] = s2 - s1
5616     //     br cond, scalar.body, exit.block
5617     //
5618     //   exit.block:
5619     //     use = lcssa.phi [s1, scalar.body]
5620     //
5621     // In this example, s1 is a recurrence because it's value depends on the
5622     // previous iteration. In the first phase of vectorization, we created a
5623     // VPFirstOrderRecurrencePHIRecipe v1 for s1. Now we create the extracts
5624     // for users in the scalar preheader and exit block.
5625     //
5626     //   vector.ph:
5627     //     v_init = vector(..., ..., ..., a[-1])
5628     //     br vector.body
5629     //
5630     //   vector.body
5631     //     i = phi [0, vector.ph], [i+4, vector.body]
5632     //     v1 = phi [v_init, vector.ph], [v2, vector.body]
5633     //     v2 = a[i, i+1, i+2, i+3]
5634     //     b[i] = v2 - v1
5635     //     // Next, third phase will introduce v1' = splice(v1(3), v2(0, 1, 2))
5636     //     b[i, i+1, i+2, i+3] = v2 - v1
5637     //     br cond, vector.body, middle.block
5638     //
5639     //   middle.block:
5640     //     vector.recur.extract.for.phi = v2(2)
5641     //     vector.recur.extract = v2(3)
5642     //     br cond, scalar.ph, exit.block
5643     //
5644     //   scalar.ph:
5645     //     scalar.recur.init = phi [vector.recur.extract, middle.block],
5646     //                             [s.init, otherwise]
5647     //     br scalar.body
5648     //
5649     //   scalar.body:
5650     //     i = phi [0, scalar.ph], [i+1, scalar.body]
5651     //     s1 = phi [scalar.recur.init, scalar.ph], [s2, scalar.body]
5652     //     s2 = a[i]
5653     //     b[i] = s2 - s1
5654     //     br cond, scalar.body, exit.block
5655     //
5656     //   exit.block:
5657     //     lo = lcssa.phi [s1, scalar.body],
5658     //                    [vector.recur.extract.for.phi, middle.block]
5659     //
5660     // Now update VPIRInstructions modeling LCSSA phis in the exit block.
5661     // Extract the penultimate value of the recurrence and use it as operand for
5662     // the VPIRInstruction modeling the phi.
5663     for (VPRecipeBase &R : make_early_inc_range(
5664              make_range(MiddleVPBB->getFirstNonPhi(), MiddleVPBB->end()))) {
5665       if (!match(&R, m_ExtractLastLaneOfLastPart(m_Specific(FOR))))
5666         continue;
5667 
5668       // For VF vscale x 1, if vscale = 1, we are unable to extract the
5669       // penultimate value of the recurrence. Instead we rely on the existing
5670       // extract of the last element from the result of
5671       // VPInstruction::FirstOrderRecurrenceSplice.
5672       // TODO: Consider vscale_range info and UF.
5673       if (LoopVectorizationPlanner::getDecisionAndClampRange(IsScalableOne,
5674                                                              Range))
5675         return;
5676       VPValue *PenultimateElement = MiddleBuilder.createNaryOp(
5677           VPInstruction::ExtractPenultimateElement, FOR->getBackedgeValue(), {},
5678           "vector.recur.extract.for.phi");
5679       cast<VPInstruction>(&R)->replaceAllUsesWith(PenultimateElement);
5680     }
5681   }
