543 Value *VPInstruction::generate(VPTransformState &State) {
544   IRBuilderBase &Builder = State.Builder;
545 
546   if (Instruction::isBinaryOp(getOpcode())) {
547     bool OnlyFirstLaneUsed = vputils::onlyFirstLaneUsed(this);
548     Value *A = State.get(getOperand(0), OnlyFirstLaneUsed);
549     Value *B = State.get(getOperand(1), OnlyFirstLaneUsed);
550     auto *Res =
551         Builder.CreateBinOp((Instruction::BinaryOps)getOpcode(), A, B, Name);
552     if (auto *I = dyn_cast<Instruction>(Res))
553       applyFlags(*I);
554     return Res;
555   }
556 
557   switch (getOpcode()) {
558   case VPInstruction::Not: {
559     bool OnlyFirstLaneUsed = vputils::onlyFirstLaneUsed(this);
560     Value *A = State.get(getOperand(0), OnlyFirstLaneUsed);
561     return Builder.CreateNot(A, Name);
562   }
