1365 bool VPInstruction::usesFirstLaneOnly(const VPValue *Op) const {
1366   assert(is_contained(operands(), Op) && "Op must be an operand of the recipe");
1367   if (Instruction::isBinaryOp(getOpcode()) || Instruction::isCast(getOpcode()))
1368     return vputils::onlyFirstLaneUsed(this);
1369 
1370   switch (getOpcode()) {
1371   default:
1372     return false;
1373   case Instruction::ExtractElement:
1374     return Op == getOperand(1);
1375   case Instruction::PHI:
1376     return true;
1377   case Instruction::FCmp:
1378   case Instruction::ICmp:
1379   case Instruction::Select:
1380   case Instruction::Or:
1381   case Instruction::Freeze:
1382   case VPInstruction::Not:
1383     // TODO: Cover additional opcodes.
1384     return vputils::onlyFirstLaneUsed(this);
1385   case VPInstruction::ActiveLaneMask:
1386   case VPInstruction::ExplicitVectorLength:
1387   case VPInstruction::CalculateTripCountMinusVF:
1388   case VPInstruction::CanonicalIVIncrementForPart:
1389   case VPInstruction::BranchOnCount:
1390   case VPInstruction::BranchOnCond:
1391   case VPInstruction::Broadcast:
1392   case VPInstruction::ReductionStartVector:
1393     return true;
1394   case VPInstruction::BuildStructVector:
1395   case VPInstruction::BuildVector:
1396     // Before replicating by VF, Build(Struct)Vector uses all lanes of the
1397     // operand, after replicating its operands only the first lane is used.
1398     // Before replicating, it will have only a single operand.
1399     return getNumOperands() > 1;
1400   case VPInstruction::PtrAdd:
1401     return Op == getOperand(0) || vputils::onlyFirstLaneUsed(this);
1402   case VPInstruction::WidePtrAdd:
1403     // WidePtrAdd supports scalar and vector base addresses.
1404     return false;
1405   case VPInstruction::ComputeAnyOfResult:
1406     return Op == getOperand(0) || Op == getOperand(1);
1407   case VPInstruction::ExitingIVValue:
1408   case VPInstruction::ExtractLane:
1409     return Op == getOperand(0);
1410   };
1411   llvm_unreachable("switch should return");
1412 }
