5671       // VPInstruction::FirstOrderRecurrenceSplice.
5672       // TODO: Consider vscale_range info and UF.
5673       if (LoopVectorizationPlanner::getDecisionAndClampRange(IsScalableOne,
5674                                                              Range))
5675         return;
