5484 /// Compute and return the end value for \p WideIV, unless it is truncated. If
5485 /// the induction recipe is not canonical, creates a VPDerivedIVRecipe to
5486 /// compute the end value of the induction.
5487 static VPValue *tryToComputeEndValueForInduction(VPWidenInductionRecipe *WideIV,
5488                                                  VPBuilder &VectorPHBuilder,
5489                                                  VPTypeAnalysis &TypeInfo,
5490                                                  VPValue *VectorTC) {
5491   auto *WideIntOrFp = dyn_cast<VPWidenIntOrFpInductionRecipe>(WideIV);
5492   // Truncated wide inductions resume from the last lane of their vector value
5493   // in the last vector iteration which is handled elsewhere.
5494   if (WideIntOrFp && WideIntOrFp->getTruncInst())
5495     return nullptr;
5496 
5497   VPIRValue *Start = WideIV->getStartValue();
5498   VPValue *Step = WideIV->getStepValue();
5499   const InductionDescriptor &ID = WideIV->getInductionDescriptor();
5500   VPValue *EndValue = VectorTC;
5501   if (!WideIntOrFp || !WideIntOrFp->isCanonical()) {
5502     EndValue = VectorPHBuilder.createDerivedIV(
5503         ID.getKind(), dyn_cast_or_null<FPMathOperator>(ID.getInductionBinOp()),
5504         Start, VectorTC, Step);
5505   }
5506 
5507   // EndValue is derived from the vector trip count (which has the same type as
5508   // the widest induction) and thus may be wider than the induction here.
5509   Type *ScalarTypeOfWideIV = TypeInfo.inferScalarType(WideIV);
5510   if (ScalarTypeOfWideIV != TypeInfo.inferScalarType(EndValue)) {
5511     EndValue = VectorPHBuilder.createScalarCast(Instruction::Trunc, EndValue,
5512                                                 ScalarTypeOfWideIV,
5513                                                 WideIV->getDebugLoc());
5514   }
5515 
5516   return EndValue;
5517 }
