8473        Plan->getVectorLoopRegion()->getEntryBasicBlock()->phis()) {
8474     VPReductionPHIRecipe *PhiR = dyn_cast<VPReductionPHIRecipe>(&R);
8475     // TODO: Remove check for constant incoming value once removeDeadRecipes is
8476     // used on VPlan0.
