8485     // and the users outside the vector region of each reduction, at the
8486     // beginning of the dedicated latch block.
8487     auto *OrigExitingVPV = PhiR->getBackedgeValue();
8488     auto *NewExitingVPV = PhiR->getBackedgeValue();
