8490     // with fewer lanes than the VF. So the operands of the select would have
8491     // different numbers of lanes. Partial reductions mask the input instead.
8492     auto *RR = dyn_cast<VPReductionRecipe>(OrigExitingVPV->getDefiningRecipe());
