8497           Builder.createSelect(Cond, OrigExitingVPV, PhiR, {}, "", *PhiR);
8498       OrigExitingVPV->replaceUsesWithIf(NewExitingVPV, [](VPUser &U, unsigned) {
8499         using namespace VPlanPatternMatch;
8500         return match(
8501             &U, m_CombineOr(
8502                     m_VPInstruction<VPInstruction::ComputeAnyOfResult>(),
8503                     m_VPInstruction<VPInstruction::ComputeReductionResult>()));
8504       });
8505 
8506       if (CM.usePredicatedReductionSelect(RecurrenceKind))
