543 Value *VPInstruction::generate(VPTransformState &State) {
544   IRBuilderBase &Builder = State.Builder;
545 
546   if (Instruction::isBinaryOp(getOpcode())) {
547     bool OnlyFirstLaneUsed = vputils::onlyFirstLaneUsed(this);
548     Value *A = State.get(getOperand(0), OnlyFirstLaneUsed);
549     Value *B = State.get(getOperand(1), OnlyFirstLaneUsed);
550     auto *Res =
551         Builder.CreateBinOp((Instruction::BinaryOps)getOpcode(), A, B, Name);
552     if (auto *I = dyn_cast<Instruction>(Res))
553       applyFlags(*I);
554     return Res;
555   }
556 
557   switch (getOpcode()) {
558   case VPInstruction::Not: {
559     bool OnlyFirstLaneUsed = vputils::onlyFirstLaneUsed(this);
560     Value *A = State.get(getOperand(0), OnlyFirstLaneUsed);
561     return Builder.CreateNot(A, Name);
562   }
563   case Instruction::ExtractElement: {
564     assert(State.VF.isVector() && "Only extract elements from vectors");
565     if (auto *Idx = dyn_cast<VPConstantInt>(getOperand(1)))
566       return State.get(getOperand(0), VPLane(Idx->getZExtValue()));
567     Value *Vec = State.get(getOperand(0));
568     Value *Idx = State.get(getOperand(1), /*IsScalar=*/true);
569     return Builder.CreateExtractElement(Vec, Idx, Name);
570   }
571   case Instruction::Freeze: {
572     Value *Op = State.get(getOperand(0), vputils::onlyFirstLaneUsed(this));
573     return Builder.CreateFreeze(Op, Name);
574   }
575   case Instruction::FCmp:
576   case Instruction::ICmp: {
577     bool OnlyFirstLaneUsed = vputils::onlyFirstLaneUsed(this);
578     Value *A = State.get(getOperand(0), OnlyFirstLaneUsed);
579     Value *B = State.get(getOperand(1), OnlyFirstLaneUsed);
580     return Builder.CreateCmp(getPredicate(), A, B, Name);
581   }
582   case Instruction::PHI: {
583     llvm_unreachable("should be handled by VPPhi::execute");
584   }
585   case Instruction::Select: {
586     bool OnlyFirstLaneUsed = vputils::onlyFirstLaneUsed(this);
587     Value *Cond =
588         State.get(getOperand(0),
589                   OnlyFirstLaneUsed || vputils::isSingleScalar(getOperand(0)));
590     Value *Op1 = State.get(getOperand(1), OnlyFirstLaneUsed);
591     Value *Op2 = State.get(getOperand(2), OnlyFirstLaneUsed);
592     return Builder.CreateSelectFMF(Cond, Op1, Op2, getFastMathFlags(), Name);
593   }
594   case VPInstruction::ActiveLaneMask: {
595     // Get first lane of vector induction variable.
596     Value *VIVElem0 = State.get(getOperand(0), VPLane(0));
597     // Get the original loop tripcount.
598     Value *ScalarTC = State.get(getOperand(1), VPLane(0));
599 
600     // If this part of the active lane mask is scalar, generate the CMP directly
601     // to avoid unnecessary extracts.
602     if (State.VF.isScalar())
603       return Builder.CreateCmp(CmpInst::Predicate::ICMP_ULT, VIVElem0, ScalarTC,
604                                Name);
605 
606     ElementCount EC = State.VF.multiplyCoefficientBy(
607         cast<VPConstantInt>(getOperand(2))->getZExtValue());
608     auto *PredTy = VectorType::get(Builder.getInt1Ty(), EC);
609     return Builder.CreateIntrinsic(Intrinsic::get_active_lane_mask,
610                                    {PredTy, ScalarTC->getType()},
611                                    {VIVElem0, ScalarTC}, nullptr, Name);
612   }
613   case VPInstruction::FirstOrderRecurrenceSplice: {
614     // Generate code to combine the previous and current values in vector v3.
615     //
616     //   vector.ph:
617     //     v_init = vector(..., ..., ..., a[-1])
618     //     br vector.body
619     //
620     //   vector.body
621     //     i = phi [0, vector.ph], [i+4, vector.body]
622     //     v1 = phi [v_init, vector.ph], [v2, vector.body]
623     //     v2 = a[i, i+1, i+2, i+3];
624     //     v3 = vector(v1(3), v2(0, 1, 2))
625 
626     auto *V1 = State.get(getOperand(0));
627     if (!V1->getType()->isVectorTy())
628       return V1;
629     Value *V2 = State.get(getOperand(1));
630     return Builder.CreateVectorSpliceRight(V1, V2, 1, Name);
631   }
632   case VPInstruction::CalculateTripCountMinusVF: {
633     Value *ScalarTC = State.get(getOperand(0), VPLane(0));
634     Value *VFxUF = State.get(getOperand(1), VPLane(0));
635     Value *Sub = Builder.CreateSub(ScalarTC, VFxUF);
636     Value *Cmp =
637         Builder.CreateICmp(CmpInst::Predicate::ICMP_UGT, ScalarTC, VFxUF);
638     Value *Zero = ConstantInt::getNullValue(ScalarTC->getType());
639     return Builder.CreateSelect(Cmp, Sub, Zero);
640   }
641   case VPInstruction::ExplicitVectorLength: {
642     // TODO: Restructure this code with an explicit remainder loop, vsetvli can
643     // be outside of the main loop.
644     Value *AVL = State.get(getOperand(0), /*IsScalar*/ true);
645     // Compute EVL
646     assert(AVL->getType()->isIntegerTy() &&
647            "Requested vector length should be an integer.");
648 
649     assert(State.VF.isScalable() && "Expected scalable vector factor.");
650     Value *VFArg = Builder.getInt32(State.VF.getKnownMinValue());
651 
652     Value *EVL = Builder.CreateIntrinsic(
653         Builder.getInt32Ty(), Intrinsic::experimental_get_vector_length,
654         {AVL, VFArg, Builder.getTrue()});
655     return EVL;
656   }
657   case VPInstruction::CanonicalIVIncrementForPart: {
658     auto *IV = State.get(getOperand(0), VPLane(0));
659     auto *VFxPart = State.get(getOperand(1), VPLane(0));
660     // The canonical IV is incremented by the vectorization factor (num of
661     // SIMD elements) times the unroll part.
662     return Builder.CreateAdd(IV, VFxPart, Name, hasNoUnsignedWrap(),
663                              hasNoSignedWrap());
664   }
665   case VPInstruction::BranchOnCond: {
666     Value *Cond = State.get(getOperand(0), VPLane(0));
667     // Replace the temporary unreachable terminator with a new conditional
668     // branch, hooking it up to backward destination for latch blocks now, and
669     // to forward destination(s) later when they are created.
670     // Second successor may be backwards - iff it is already in VPBB2IRBB.
671     VPBasicBlock *SecondVPSucc =
672         cast<VPBasicBlock>(getParent()->getSuccessors()[1]);
673     BasicBlock *SecondIRSucc = State.CFG.VPBB2IRBB.lookup(SecondVPSucc);
674     BasicBlock *IRBB = State.CFG.VPBB2IRBB[getParent()];
675     auto *Br = Builder.CreateCondBr(Cond, IRBB, SecondIRSucc);
676     // First successor is always forward, reset it to nullptr.
677     Br->setSuccessor(0, nullptr);
678     IRBB->getTerminator()->eraseFromParent();
679     applyMetadata(*Br);
680     return Br;
681   }
682   case VPInstruction::Broadcast: {
683     return Builder.CreateVectorSplat(
684         State.VF, State.get(getOperand(0), /*IsScalar*/ true), "broadcast");
685   }
686   case VPInstruction::BuildStructVector: {
687     // For struct types, we need to build a new 'wide' struct type, where each
688     // element is widened, i.e., we create a struct of vectors.
689     auto *StructTy =
690         cast<StructType>(State.TypeAnalysis.inferScalarType(getOperand(0)));
691     Value *Res = PoisonValue::get(toVectorizedTy(StructTy, State.VF));
692     for (const auto &[LaneIndex, Op] : enumerate(operands())) {
693       for (unsigned FieldIndex = 0; FieldIndex != StructTy->getNumElements();
694            FieldIndex++) {
695         Value *ScalarValue =
696             Builder.CreateExtractValue(State.get(Op, true), FieldIndex);
697         Value *VectorValue = Builder.CreateExtractValue(Res, FieldIndex);
698         VectorValue =
699             Builder.CreateInsertElement(VectorValue, ScalarValue, LaneIndex);
700         Res = Builder.CreateInsertValue(Res, VectorValue, FieldIndex);
701       }
702     }
703     return Res;
704   }
705   case VPInstruction::BuildVector: {
706     auto *ScalarTy = State.TypeAnalysis.inferScalarType(getOperand(0));
707     auto NumOfElements = ElementCount::getFixed(getNumOperands());
708     Value *Res = PoisonValue::get(toVectorizedTy(ScalarTy, NumOfElements));
709     for (const auto &[Idx, Op] : enumerate(operands()))
710       Res = Builder.CreateInsertElement(Res, State.get(Op, true),
711                                         Builder.getInt32(Idx));
712     return Res;
713   }
714   case VPInstruction::ReductionStartVector: {
715     if (State.VF.isScalar())
716       return State.get(getOperand(0), true);
717     IRBuilderBase::FastMathFlagGuard FMFG(Builder);
718     Builder.setFastMathFlags(getFastMathFlags());
719     // If this start vector is scaled then it should produce a vector with fewer
720     // elements than the VF.
721     ElementCount VF = State.VF.divideCoefficientBy(
722         cast<VPConstantInt>(getOperand(2))->getZExtValue());
723     auto *Iden = Builder.CreateVectorSplat(VF, State.get(getOperand(1), true));
724     return Builder.CreateInsertElement(Iden, State.get(getOperand(0), true),
725                                        Builder.getInt32(0));
726   }
727   case VPInstruction::ComputeAnyOfResult: {
728     Value *Start = State.get(getOperand(0), VPLane(0));
729     Value *NewVal = State.get(getOperand(1), VPLane(0));
730     Value *ReducedResult = State.get(getOperand(2));
731     for (unsigned Idx = 3; Idx < getNumOperands(); ++Idx)
732       ReducedResult =
733           Builder.CreateBinOp(Instruction::Or, State.get(getOperand(Idx)),
734                               ReducedResult, "bin.rdx");
735     // If any predicate is true it means that we want to select the new value.
736     if (ReducedResult->getType()->isVectorTy())
737       ReducedResult = Builder.CreateOrReduce(ReducedResult);
738     // The compares in the loop may yield poison, which propagates through the
739     // bitwise ORs. Freeze it here before the condition is used.
740     ReducedResult = Builder.CreateFreeze(ReducedResult);
741     return Builder.CreateSelect(ReducedResult, NewVal, Start, "rdx.select");
742   }
743   case VPInstruction::ComputeReductionResult: {
744     RecurKind RK = getRecurKind();
745     bool IsOrdered = isReductionOrdered();
746     bool IsInLoop = isReductionInLoop();
747     assert(!RecurrenceDescriptor::isFindIVRecurrenceKind(RK) &&
748            "FindIV should use min/max reduction kinds");
749 
750     // The recipe may have multiple operands to be reduced together.
751     unsigned NumOperandsToReduce = getNumOperands();
752     VectorParts RdxParts(NumOperandsToReduce);
753     for (unsigned Part = 0; Part < NumOperandsToReduce; ++Part)
754       RdxParts[Part] = State.get(getOperand(Part), IsInLoop);
755 
756     IRBuilderBase::FastMathFlagGuard FMFG(Builder);
757     Builder.setFastMathFlags(getFastMathFlags());
758 
759     // Reduce multiple operands into one.
760     Value *ReducedPartRdx = RdxParts[0];
761     if (IsOrdered) {
762       ReducedPartRdx = RdxParts[NumOperandsToReduce - 1];
763     } else {
764       // Floating-point operations should have some FMF to enable the reduction.
765       for (unsigned Part = 1; Part < NumOperandsToReduce; ++Part) {
766         Value *RdxPart = RdxParts[Part];
767         if (RecurrenceDescriptor::isMinMaxRecurrenceKind(RK))
768           ReducedPartRdx = createMinMaxOp(Builder, RK, ReducedPartRdx, RdxPart);
769         else {
770           // For sub-recurrences, each part's reduction variable is already
771           // negative, we need to do: reduce.add(-acc_uf0 + -acc_uf1)
772           Instruction::BinaryOps Opcode =
773               RK == RecurKind::Sub
774                   ? Instruction::Add
775                   : (Instruction::BinaryOps)RecurrenceDescriptor::getOpcode(RK);
776           ReducedPartRdx =
777               Builder.CreateBinOp(Opcode, RdxPart, ReducedPartRdx, "bin.rdx");
778         }
779       }
780     }
781 
782     // Create the reduction after the loop. Note that inloop reductions create
783     // the target reduction in the loop using a Reduction recipe.
784     if (State.VF.isVector() && !IsInLoop) {
785       // TODO: Support in-order reductions based on the recurrence descriptor.
786       // All ops in the reduction inherit fast-math-flags from the recurrence
787       // descriptor.
788       ReducedPartRdx = createSimpleReduction(Builder, ReducedPartRdx, RK);
789     }
