439 unsigned VPInstruction::getNumOperandsForOpcode() const {
440   if (Instruction::isUnaryOp(Opcode) || Instruction::isCast(Opcode))
441     return 1;
442 
443   if (Instruction::isBinaryOp(Opcode))
444     return 2;
445 
446   switch (Opcode) {
447   case VPInstruction::StepVector:
448   case VPInstruction::VScale:
449     return 0;
450   case Instruction::Alloca:
451   case Instruction::ExtractValue:
452   case Instruction::Freeze:
453   case Instruction::Load:
454   case VPInstruction::BranchOnCond:
455   case VPInstruction::Broadcast:
456   case VPInstruction::ExitingIVValue:
457   case VPInstruction::ExplicitVectorLength:
458   case VPInstruction::ExtractLastLane:
459   case VPInstruction::ExtractLastPart:
460   case VPInstruction::ExtractPenultimateElement:
461   case VPInstruction::MaskedCond:
462   case VPInstruction::Not:
463   case VPInstruction::ResumeForEpilogue:
464   case VPInstruction::Reverse:
465   case VPInstruction::Unpack:
466     return 1;
467   case Instruction::ICmp:
468   case Instruction::FCmp:
469   case Instruction::ExtractElement:
470   case Instruction::Store:
471   case VPInstruction::BranchOnCount:
472   case VPInstruction::BranchOnTwoConds:
473   case VPInstruction::FirstOrderRecurrenceSplice:
474   case VPInstruction::LogicalAnd:
475   case VPInstruction::LogicalOr:
476   case VPInstruction::PtrAdd:
477   case VPInstruction::WidePtrAdd:
478   case VPInstruction::WideIVStep:
479   case VPInstruction::CalculateTripCountMinusVF:
480     return 2;
481   case Instruction::Select:
482   case VPInstruction::ActiveLaneMask:
483   case VPInstruction::ReductionStartVector:
484   case VPInstruction::ExtractLastActive:
485     return 3;
486   case Instruction::Call: {
487     // For unmasked calls, the last argument will the called function. Use that
488     // to compute the number of operands without the mask.
489     VPValue *LastOp = getOperand(getNumOperands() - 1);
490     if (isa<VPIRValue>(LastOp) && isa<Function>(LastOp->getLiveInIRValue()))
491       return getNumOperands();
492     return getNumOperands() - 1;
493   }
494   case Instruction::GetElementPtr:
495   case Instruction::PHI:
496   case Instruction::Switch:
497   case VPInstruction::AnyOf:
498   case VPInstruction::BuildStructVector:
499   case VPInstruction::BuildVector:
500   case VPInstruction::CanonicalIVIncrementForPart:
501   case VPInstruction::ComputeAnyOfResult:
502   case VPInstruction::ComputeReductionResult:
503   case VPInstruction::FirstActiveLane:
504   case VPInstruction::LastActiveLane:
505   case VPInstruction::SLPLoad:
506   case VPInstruction::SLPStore:
507   case VPInstruction::ExtractLane:
508     // Cannot determine the number of operands from the opcode.
509     return -1u;
510   }
511   llvm_unreachable("all cases should be handled above");
512 }
