5684 void VPlanTransforms::optimizeFindIVReductions(VPlan &Plan,
5685                                                PredicatedScalarEvolution &PSE,
5686                                                Loop &L) {
5687   ScalarEvolution &SE = *PSE.getSE();
5688   VPRegionBlock *VectorLoopRegion = Plan.getVectorLoopRegion();
5689 
5690   // Helper lambda to check if the IV range excludes the sentinel value.
5691   auto CheckSentinel = [&SE](const SCEV *IVSCEV, bool UseMax,
5692                              bool Signed) -> std::optional<APInt> {
5693     unsigned BW = IVSCEV->getType()->getScalarSizeInBits();
5694     APInt Sentinel =
5695         UseMax
5696             ? (Signed ? APInt::getSignedMinValue(BW) : APInt::getMinValue(BW))
5697             : (Signed ? APInt::getSignedMaxValue(BW) : APInt::getMaxValue(BW));
5698 
5699     ConstantRange IVRange =
5700         Signed ? SE.getSignedRange(IVSCEV) : SE.getUnsignedRange(IVSCEV);
5701     if (!IVRange.contains(Sentinel))
5702       return Sentinel;
5703     return std::nullopt;
5704   };
5705 
5706   VPValue *HeaderMask = vputils::findHeaderMask(Plan);
5707   for (VPRecipeBase &Phi :
5708        make_early_inc_range(VectorLoopRegion->getEntryBasicBlock()->phis())) {
5709     auto *PhiR = dyn_cast<VPReductionPHIRecipe>(&Phi);
5710     if (!PhiR || !RecurrenceDescriptor::isFindLastRecurrenceKind(
5711                      PhiR->getRecurrenceKind()))
5712       continue;
5713 
5714     // If there's a header mask, the backedge select will not be the find-last
5715     // select.
5716     VPValue *BackedgeVal = PhiR->getBackedgeValue();
5717     VPValue *CondSelect = BackedgeVal;
5718     if (HeaderMask &&
5719         !match(BackedgeVal, m_Select(m_Specific(HeaderMask),
5720                                      m_VPValue(CondSelect), m_Specific(PhiR))))
5721       llvm_unreachable("expected header mask select");
5722 
5723     // Get the IV from the conditional select of the reduction phi.
5724     // The conditional select should be a select between the phi and the IV.
5725     VPValue *Cond, *TrueVal, *FalseVal;
5726     if (!match(CondSelect, m_Select(m_VPValue(Cond), m_VPValue(TrueVal),
5727                                     m_VPValue(FalseVal))))
5728       continue;
5729 
5730     // The non-phi operand of the select is the IV.
5731     assert(is_contained(CondSelect->getDefiningRecipe()->operands(), PhiR));
5732     VPValue *IV = TrueVal == PhiR ? FalseVal : TrueVal;
5733 
5734     const SCEV *IVSCEV = vputils::getSCEVExprForVPValue(IV, PSE, &L);
5735     const SCEV *Step;
5736     if (!match(IVSCEV, m_scev_AffineAddRec(m_SCEV(), m_SCEV(Step))))
5737       continue;
5738 
5739     // Determine direction from SCEV step.
5740     if (!SE.isKnownNonZero(Step))
5741       continue;
5742 
5743     // Positive step means we need UMax/SMax to find the last IV value, and
5744     // UMin/SMin otherwise.
